// ------------------------------------------------------------
// Physical Sensing Components
// ------------------------------------------------------------

instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring hoist swing"
    DTDFVocab:producedData SwingAngleMeasurement
]

instance AnemometerSensor : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed"
    DTDFVocab:producedData WindSpeedMeasurement
]

instance MotorStatusFeedbackSensor : DTDFVocab:SensingComponent [
    base:desc "Arduino‑read motor status feedback from the controllers"
    DTDFVocab:producedData MotorStatusMessage
]

// ------------------------------------------------------------
// Physical Acting Components
// ------------------------------------------------------------

instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Cart stepper motor driven by a TMC4671‑Eval controller"
]

instance HoistStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Hoist stepper motor driven by a TMC4671‑Eval controller"
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the hoist end, energizable/de‑energizable via Arduino"
]

// ------------------------------------------------------------
// Data Transmitted (Physical → Virtual)
// ------------------------------------------------------------

instance SwingAngleMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder
]

instance WindSpeedMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom AnemometerSensor
]

instance MotorStatusMessage : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorStatusFeedbackSensor
]

instance GeneratedTrajectoryMessage : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TrajectoryGeneratorService
]

instance SimulatedStateTraceMessage : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SimulationService
]

// ------------------------------------------------------------
// Data (Virtual)
// ------------------------------------------------------------

instance SensorMeasurementData : DTDFVocab:Data [
    base:desc "Time‑series sensor measurements stored in TimescaleDB"
    DTDFVocab:fromData SwingAngleMeasurement, WindSpeedMeasurement, MotorStatusMessage
    DTDFVocab:inputTo TimescaleDB
]

instance GeneratedTrajectoryData : DTDFVocab:Data [
    base:desc "Optimal trajectories generated by the Trajectory Generator"
    DTDFVocab:fromData GeneratedTrajectoryMessage
    DTDFVocab:inputTo TimescaleDB
]

instance SimulatedStateTraceData : DTDFVocab:Data [
    base:desc "State traces produced by the Simulation Service for validation"
    DTDFVocab:fromData SimulatedStateTraceMessage
    DTDFVocab:inputTo TimescaleDB
]

// ------------------------------------------------------------
// Models
// ------------------------------------------------------------

instance CADGeometryModel : DTDFVocab:Model [
    base:desc "CAD geometry of the crane"
    DTDFVocab:inputTo CADModelEnabler
]

instance KinematicCraneModel : DTDFVocab:Model [
    base:desc "Kinematic model used for trajectory planning and simulation"
    DTDFVocab:inputTo KinematicModelEnabler
]

// ------------------------------------------------------------
// Enablers (Software / Infrastructure)
// ------------------------------------------------------------

instance MQTTBrokerMosquitto : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker used by the Physical Crane Interface to publish sensor and motor state"
    DTDFVocab:enables RealTimeLoggingService,
                   VisualizationDashboardService,
                   TrajectoryGeneratorService,
                   SimulationService,
                   ContinuousValidationService,
                   HumanMachineInterfaceService
]

instance TimescaleDB : DTDFVocab:Enabler [
    base:desc "TimescaleDB PostgreSQL time‑series database persisting sensor measurements, trajectories and simulation traces"
    DTDFVocab:enables RealTimeLoggingService,
                   ContinuousValidationService
]

instance KinematicModelEnabler : DTDFVocab:Enabler [
    base:desc "Software component that consumes the kinematic model to compute optimal trajectories"
    DTDFVocab:enables TrajectoryGeneratorService
]

instance CADModelEnabler : DTDFVocab:Enabler [
    base:desc "Simulation engine that uses the CAD geometry model to compute crane dynamics"
    DTDFVocab:enables SimulationService
]

instance GrafanaVisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Grafana container visualizing logged data for operators"
    DTDFVocab:enables VisualizationDashboardService
]

// ------------------------------------------------------------
// Services
// ------------------------------------------------------------

instance RealTimeLoggingService : DTDFVocab:Service [
    base:desc "Real‑time data logging service that stores incoming measurements into TimescaleDB"
    DTDFVocab:provides SystemHealthInsight,
                   ModelDeviationAlertInsight
]

instance VisualizationDashboardService : DTDFVocab:Service [
    base:desc "Grafana‑based dashboards enabling operators to assess system health"
    DTDFVocab:provides SystemHealthInsight
]

instance TrajectoryGeneratorService : DTDFVocab:Service [
    base:desc "Generates optimal swing‑free movement plans using the kinematic model"
    DTDFVocab:provides SwingFreeTrajectoryInsight,
                   StartTrajectoryExecutionAction
]

instance SimulationService : DTDFVocab:Service [
    base:desc "Simulates crane dynamics based on CAD geometry and kinematic model, producing state traces"
    DTDFVocab:provides SimulatedStateTraceInsight,
                   AdjustControlParametersAction
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Continuously validates executed trajectories against simulated ones and raises alerts on deviations"
    DTDFVocab:provides ModelDeviationAlertInsight,
                   CorrectiveAction
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "Human‑Machine Interface allowing operators to monitor health and trigger corrective actions"
    DTDFVocab:provides SystemHealthInsight,
                   CorrectiveAction
]

// ------------------------------------------------------------
// Insights
// ------------------------------------------------------------

instance ModelDeviationAlertInsight : DTDFVocab:Insight [
    base:desc "Alert indicating deviation between executed and simulated trajectories"
]

instance SwingFreeTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Provides an optimal swing‑free trajectory plan for the crane"
]

instance SystemHealthInsight : DTDFVocab:Insight [
    base:desc "Aggregated view of system health derived from sensor data and logs"
]

instance SimulatedStateTraceInsight : DTDFVocab:Insight [
    base:desc "Insight extracted from simulated state traces used for validation"
]

// ------------------------------------------------------------
// Actions
// ------------------------------------------------------------

instance StartTrajectoryExecutionAction : DTDFVocab:Action [
    base:desc "Command to start execution of a generated trajectory"
    DTDFVocab:IsAutomatic false
]

instance AdjustControlParametersAction : DTDFVocab:Action [
    base:desc "Automatically adjust motor controller parameters based on simulation feedback"
    DTDFVocab:IsAutomatic true
]

instance CorrectiveAction : DTDFVocab:Action [
    base:desc "Operator‑initiated corrective action to mitigate identified issues"
    DTDFVocab:IsAutomatic false
]

// ------------------------------------------------------------
// Environment and Physical Components
// ------------------------------------------------------------

